INSERT INTO OM_DEPLOY_REQUEST (
  DEPLOY_REQUEST_ID, REQUEST_TYPE, ENV_CODE, BUSINESS_CODE, MODULE_NAME,
  BRANCH_NAME, COMMIT_ID, GRADLE_TASK, ARTIFACT_NAME, STATUS,
  REQUEST_USER_ID, APPROVE_USER_ID, REQUEST_TIME, APPROVE_TIME, START_TIME, END_TIME, ERROR_MESSAGE
) VALUES (
  #{deployRequestId}, #{requestType}, #{envCode}, #{businessCode}, #{moduleName},
  #{branchName}, #{commitId}, #{gradleTask}, #{artifactName}, #{status},
  #{requestUserId}, #{approveUserId}, #{requestTime}, #{approveTime}, #{startTime}, #{endTime}, #{errorMessage}
)

mapper.update:
UPDATE OM_DEPLOY_REQUEST
STATUS = #{status}, APPROVE_USER_ID = #{approveUserId}, APPROVE_TIME = #{approveTime}, START_TIME = #{startTime}, END_TIME = #{endTime}, ERROR_MESSAGE = #{errorMessage}, ARTIFACT_NAME = #{artifactName},
WHERE DEPLOY_REQUEST_ID = #{deployRequestId}

mapper.select:
SELECT 
FROM OM_DEPLOY_REQUEST

  AND REQUEST_TYPE = #{requestType}
  AND ENV_CODE = #{envCode}
  AND BUSINESS_CODE = #{businessCode}
  AND STATUS = #{status}
  AND MODULE_NAME = #{moduleName}

ORDER BY REQUEST_TIME DESC
OFFSET #{offset} ROWS FETCH NEXT #{pageSize} ROWS ONLY

SELECT COUNT(*)
FROM OM_DEPLOY_REQUEST

  AND REQUEST_TYPE = #{requestType}
  AND ENV_CODE = #{envCode}
  AND BUSINESS_CODE = #{businessCode}
  AND STATUS = #{status}
  AND MODULE_NAME = #{moduleName}

