INSERT INTO OM_DEPLOY_HISTORY (
  DEPLOY_HISTORY_ID, DEPLOY_REQUEST_ID, ENV_CODE, TARGET_SERVER, CONTEXT_PATH,
  BEFORE_VERSION, AFTER_VERSION, RESULT_CODE, RESULT_MESSAGE,
  HEALTH_CHECK_URL, HEALTH_CHECK_RESULT, CREATED_TIME
) VALUES (
  #{deployHistoryId}, #{deployRequestId}, #{envCode}, #{targetServer}, #{contextPath},
  #{beforeVersion}, #{afterVersion}, #{resultCode}, #{resultMessage},
  #{healthCheckUrl}, #{healthCheckResult}, #{createdTime}
)

mapper.select:
SELECT DEPLOY_HISTORY_ID AS "deployHistoryId", DEPLOY_REQUEST_ID AS "deployRequestId", ENV_CODE AS "envCode", TARGET_SERVER AS "targetServer", CONTEXT_PATH AS "contextPath", BEFORE_VERSION AS "beforeVersion", AFTER_VERSION AS "afterVersion", RESULT_CODE AS "resultCode", RESULT_MESSAGE AS "resultMessage", HEALTH_CHECK_URL AS "healthCheckUrl", HEALTH_CHECK_RESULT AS "healthCheckResult", CREATED_TIME AS "createdTime" FROM OM_DEPLOY_HISTORY
AND DEPLOY_REQUEST_ID = #{deployRequestId} AND ENV_CODE = #{envCode} AND RESULT_CODE = #{resultCode}
ORDER BY CREATED_TIME DESC OFFSET #{offset} ROWS FETCH NEXT #{pageSize} ROWS ONLY

SELECT COUNT(*)
FROM OM_DEPLOY_HISTORY

  AND DEPLOY_REQUEST_ID = #{deployRequestId}
  AND ENV_CODE = #{envCode}
  AND RESULT_CODE = #{resultCode}
